import { useState, useEffect, useRef } from "react";

/* ─── Data ──────────────────────────────────────────────────────────── */
const MILES = [
  {
    id: "first",
    label: "First Mile",
    image: "/Mile.png",
    items: [
      {
        num: 1,
        title: "Warehouse pickers",
        desc: "Responsible for sorting goods at origin warehouses before dispatch.",
      },
      {
        num: 2,
        title: "Dark-store associates",
        desc: "Operate out of high-density storage units in residential clusters.",
      },
      {
        num: 3,
        title: "Aggregation-hub handlers",
        desc: "Consolidate incoming shipments and prepare them for onward dispatch.",
      },
    ],
  },
  {
    id: "middle",
    label: "Middle Mile",
    image: "/Mile.png",
    items: [
      {
        num: 1,
        title: "Truck drivers",
        desc: "Transport goods between warehouses, hubs, and cities.",
      },
      {
        num: 2,
        title: "Fleet operators",
        desc: "Manage movement from aggregation hubs to local distribution points.",
      },
    ],
  },
  {
    id: "last",
    label: "Last Mile",
    image: "/Mile.png",
    items: [
      {
        num: 1,
        title: "Delivery partners",
        desc: "Handle final doorstep delivery — food, groceries, and parcels.",
      },
      {
        num: 2,
        title: "Hyperlocal riders",
        desc: "Factors such as high attrition, constant churn, frequent relocation, and flexible partner-based models (vs. full-time employment) increase verification complexity and compliance risk across these segments.",
      },
    ],
  },
];

const DURATION = 500; // ms
const EASE     = "cubic-bezier(0.4, 0, 0.2, 1)";

/* ─── Content layout ────────────────────────────────────────────────── */
function MileContent({ mile }) {
  return (
    <div style={{
      display: "flex",
      gap: 80,
      alignItems: "flex-start",
      width: "100%",
    }}>
      {/* Image */}
      <div style={{
        flexShrink: 0,
        width: 340, height: 380,
        borderRadius: 10,
        overflow: "hidden",
        border: "1px solid #e8e8e8",
        background: "#f0eeeb",
        position: "relative",
      }}>
        <img
          src={mile.image}
          alt={mile.label}
          style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
          onError={e => {
            e.target.style.display = "none";
            const fb = e.target.parentNode.querySelector(".mile-fallback");
            if (fb) fb.style.display = "flex";
          }}
        />
        {/* Fallback BW collage if Mile.png is missing */}
        <div className="mile-fallback" style={{
          display: "none", position: "absolute", inset: 0,
          background: "linear-gradient(145deg,#ccc 0%,#aaa 55%,#999 100%)",
          alignItems: "center", justifyContent: "center",
        }}>
          <div style={{ position:"absolute", top:28, left:22, width:36, height:36, background:"#e53e3e" }}/>
          <div style={{
            position:"absolute", bottom:60, right:24,
            width:0, height:0,
            borderLeft:"14px solid transparent",
            borderRight:"14px solid transparent",
            borderBottom:"24px solid #1a3a6b",
          }}/>
          <div style={{
            width:160, height:70,
            background:"rgba(40,40,40,0.55)",
            borderRadius:"6px 6px 0 0",
            position:"absolute", bottom:50, left:20,
          }}/>
          <div style={{
            position:"absolute", bottom:28, right:14,
            width:40, height:40,
            backgroundImage:"radial-gradient(circle,#888 1px,transparent 1px)",
            backgroundSize:"6px 6px", opacity:0.45,
          }}/>
          <div style={{
            position:"absolute", bottom:12, left:14, right:14,
            background:"rgba(255,255,255,0.88)", padding:"5px 10px",
            borderRadius:3, fontSize:10, color:"#333",
            fontStyle:"italic", fontFamily:"Georgia,serif",
          }}>Motor Insurance.</div>
        </div>
      </div>

      {/* Text items */}
      <div style={{ flex:1, paddingTop:10 }}>
        {mile.items.map((item, i) => (
          <div key={i} style={{ marginBottom: 40 }}>
            <h3 style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(18px,1.5vw,24px)",
              fontWeight: 700,
              color: "#1a3a6b",
              marginBottom: 10,
            }}>
              {item.num}.&nbsp;{item.title}
            </h3>
            <p style={{
              fontSize: "clamp(14px,1.05vw,17px)",
              color: "#444", lineHeight: 1.8,
              fontFamily: "'Inter',sans-serif",
            }}>{item.desc}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

/* ─── Main component ────────────────────────────────────────────────── */
export default function PeopleSection() {
  const [active,   setActive]   = useState(0);
  const [leaving,  setLeaving]  = useState(null);   // index leaving
  const [incoming, setIncoming] = useState(null);   // index arriving
  const [phase,    setPhase]    = useState("idle");
  // "idle" | "exit" (old slides out) | "enter" (new slides in)
  const [dir, setDir] = useState("left");
  const timer = useRef(null);

  const go = (idx) => {
    if (idx === active || phase !== "idle") return;

    const d = idx > active ? "left" : "right";
    setDir(d);
    setLeaving(active);
    setIncoming(idx);
    setPhase("exit");

    // After old panel exits, swap and bring in new panel
    timer.current = setTimeout(() => {
      setActive(idx);
      setLeaving(null);
      setPhase("enter");

      timer.current = setTimeout(() => {
        setIncoming(null);
        setPhase("idle");
      }, DURATION + 20);
    }, DURATION);
  };

  useEffect(() => () => clearTimeout(timer.current), []);

  // CSS transform values per phase
  const outTranslate = dir === "left" ? "-100%" : "100%";
  const inTranslate  = dir === "left" ? "100%"  : "-100%";

  return (
    <section style={{ background:"#fff", padding:"100px 6vw 120px" }}>
      <style>{`
        @keyframes pulse-active {
          0%   { transform:scale(1);   opacity:.9; }
          100% { transform:scale(1.9); opacity:0;  }
        }
      `}</style>

      {/* Heading */}
      <div style={{ textAlign:"center", marginBottom:64 }}>
        <h2 style={{
          fontFamily:"'Playfair Display','Georgia',serif",
          fontSize:"clamp(40px,7vw,96px)",
          fontWeight:900, color:"#1a1a1a",
          lineHeight:1.05, margin:"0 0 22px",
        }}>
          The people who<br/>powered this evolution
        </h2>
        <p style={{
          fontSize:"clamp(15px,1.15vw,20px)",
          color:"#555", lineHeight:1.7,
          maxWidth:700, margin:"0 auto",
          fontFamily:"'Inter',sans-serif",
        }}>
          The gig workforce spans the entire supply chain, from first-mile
          operations to last-mile delivery.
        </p>
      </div>

      {/* Timeline bar */}
      <div style={{
        position:"relative",
        maxWidth:900, margin:"0 auto 60px",
        padding:"0 80px",
      }}>
        {/* Horizontal red line */}
        <div style={{
          position:"absolute",
          top:"calc(100% - 8px)",
          left:80, right:80,
          height:2, background:"#e53e3e", zIndex:0,
        }}/>

        <div style={{
          display:"flex", justifyContent:"space-between",
          alignItems:"flex-end", position:"relative", zIndex:1,
        }}>
          {MILES.map((mile, i) => {
            const isActive = active === i;
            return (
              <button
                key={mile.id}
                onClick={() => go(i)}
                style={{
                  background:"none", border:"none",
                  cursor: phase !== "idle" ? "default" : "pointer",
                  display:"flex", flexDirection:"column",
                  alignItems:"center", gap:8, padding:0,
                }}
              >
                <span style={{
                  fontFamily:"'Inter',sans-serif",
                  fontSize:16, fontWeight:700, color:"#e53e3e",
                  opacity: isActive ? 1 : 0.55,
                  transition:"opacity 0.3s",
                }}>{mile.label}</span>

                <div style={{
                  width: isActive ? 28 : 18,
                  height: isActive ? 28 : 18,
                  borderRadius:"50%",
                  background:"#e53e3e",
                  border: isActive ? "3px solid white" : "none",
                  boxShadow: isActive ? "0 0 0 3px #e53e3e" : "none",
                  transition:`all 0.35s cubic-bezier(0.34,1.56,0.64,1)`,
                  position:"relative",
                }}>
                  {isActive && (
                    <span style={{
                      position:"absolute", inset:-7, borderRadius:"50%",
                      border:"2px solid rgba(229,62,62,0.35)",
                      animation:"pulse-active 1.6s ease-out infinite",
                    }}/>
                  )}
                </div>
              </button>
            );
          })}
        </div>
      </div>

      {/* Slide content area */}
      <div style={{ maxWidth:1280, margin:"0 auto" }}>
        {/* Tab label */}
        <p style={{
          fontSize:12, fontWeight:700, color:"#e53e3e",
          letterSpacing:1.5, textTransform:"uppercase",
          marginBottom:32, fontFamily:"'Inter',sans-serif",
        }}>{MILES[active].label}</p>

        {/* Overflow clip wrapper */}
        <div style={{ position:"relative", overflow:"hidden", minHeight:400 }}>

          {/* Leaving panel — slides OUT */}
          {leaving !== null && phase === "exit" && (
            <div style={{
              position:"absolute", top:0, left:0, right:0,
              transform:`translateX(${outTranslate})`,
              opacity:0,
              transition:`transform ${DURATION}ms ${EASE}, opacity ${DURATION}ms ${EASE}`,
            }}>
              <MileContent mile={MILES[leaving]}/>
            </div>
          )}

          {/* Active / incoming panel */}
          <div style={{
            // During "exit" phase: sits at inTranslate (off-screen), waiting
            // During "enter" phase: animates from inTranslate → 0
            // During "idle": sits at 0
            transform: phase === "exit"
              ? `translateX(${inTranslate})`
              : "translateX(0)",
            opacity: phase === "exit" ? 0 : 1,
            transition: phase === "enter"
              ? `transform ${DURATION}ms ${EASE}, opacity ${DURATION}ms ${EASE}`
              : "none",
          }}>
            <MileContent mile={MILES[active]}/>
          </div>

        </div>
      </div>
    </section>
  );
}
